 "dy_dx of y=x^2 at x=3.0 is: tensor(6.)\n"
 ]
 }
 ],
 "source": [
 "### Gradient computation ###\n",
 "\n",
 "# y = x^2\n",
 "# Example: x = 3.0\n",
 "x = torch.tensor(3.0, requires_grad=True)\n",
 "y = x ** 2\n",
 "y.backward() # Compute the gradient\n",
 "\n",
 "dy_dx = x.grad\n",
 "print(\"dy_dx of y=x^2 at x=3.0 is: \", dy_dx)\n",
 "assert dy_dx == 6.0\n"
 ]
 },
